+function normalizeCursorSort(orderBy: any, idField: string): CursorSort[] {
+  const entries = (Array.isArray(orderBy) ? orderBy : [orderBy]).flatMap(
+    (part) => Object.entries(part || {}),
+  );
+  const sorts = entries.map(([field, direction]) => {
