+  if (!sorts.some((sort) => sort.field === idField)) {
+    sorts.push({ field: idField, direction: 'asc' });
+  }
+  return sorts;
+}
+
+function getCursorValue(entity: any, field: string) {
+  return field.split('.').reduce((value, key) => value?.[key], entity);
+}
+
+function decodeCursor(cursor: string, sorts: CursorSort[], idField: string) {
+  let decoded: any;
+  try {
+    if (
