+      const comparison: Record<string, any> = {};
+      for (let previousIndex = 0; previousIndex < index; previousIndex++) {
+        const previous = sorts[previousIndex];
+        comparison[previous.field] = cursor[previous.field];
+      }
+      comparison[sort.field] = {
+        [sort.direction === 'asc' ? '$gt' : '$lt']: cursor[sort.field],
+      };
+      return comparison;
+    }),
+  };
