export class CrudAuthorizationService {
  protected crudConfig: CrudConfigService;
  rolesMap: Record<string, CrudRole> = {};
  constructor(protected moduleRef: ModuleRef) {}

  onModuleInit() {
    this.crudConfig = this.moduleRef.get(CRUD_CONFIG_KEY, { strict: false });
    this.rolesMap = this.crudConfig.rolesMap;
  }

  getCtxUserRole(ctx: CrudContext): CrudRole {
    const role = ctx.user?.role || this.crudConfig.guest_role;
    return this.rolesMap[role];
  }

  getUserRole(user: CrudUser): CrudRole {
    const role = user?.role || this.crudConfig.guest_role;
    return this.rolesMap[role];
  }

  getMatchBatchSizeFromCrudRoleAndParents(
    ctx: CrudContext,
    userRole: CrudRole,
    security: CrudSecurity | CmdSecurity,
  ) {
    const roleRights: CrudSecurityRights | CmdSecurityRights =
      security.rolesRights?.[userRole.name] || ({} as any);

    let maxBatchSize = roleRights?.maxBatchSize || 0;

    if (userRole.inherits?.length) {
      for (const parent of userRole.inherits) {
        const parentRole = this.rolesMap[parent];
        const parentMaxBatchSize = this.getMatchBatchSizeFromCrudRoleAndParents(
          ctx,
          parentRole,
          security,
      app.addHook('preValidation', async (request, reply) => {
        if (request.url.includes('/crud/s')) {
          const serviceName = request.url.split('/crud/s/')[1].split('/')[0];
          const url = registered[serviceName];
          if (url) {
            const rest = request.url;
            request.headers['x-forwarded-for'] = request.ip;
            return await reply.from(url + rest);
          }
        }
      });
    }
  }

  assignContext(
    method: 'POST' | 'GET' | 'PATCH' | 'DELETE',
    crudQuery: CrudQuery,
    query: any,
    data: any,
    type,
    ctx: CrudContext,
  ): CrudService<any> {
    const currentService: CrudService<any> =
      this.crudConfig.servicesMap[crudQuery?.service];
    this.checkServiceNotFound(currentService, crudQuery);
    ctx.method = method;
    ctx.serviceName = crudQuery.service;
    ctx.query = query;
    ctx.data = data;
    ctx.queryOptions = crudQuery.options;
    ctx.origin = type;

    ctx._temp = ctx._temp || {};
    ctx.store = ctx.store || {};

    ctx.getCurrentService = () => currentService;

    if (ctx.origin == 'cmd') {
      ctx.cmdName = crudQuery.cmd;
    }
    return currentService;
  }

  async beforeHooks(service: CrudService<any>, ctx: CrudContext) {
    //await service.beforeControllerHook(ctx);
    await this.crudConfig.beforeControllerHook(ctx);
    if (ctx.origin == 'cmd') {
      const cmdSecurity: CmdSecurity =
